    public void handleOrderBook(Client client, Object message)
    {
        //
        //     {
        //         "topic": "orderbook25.H.BTCUSDT",
        //         "type": "snapshot",
        //         "ts": 1672304484978,
        //         "data": {
        //             "s": "BTCUSDT",
        //             "b": [
        //                 ...,
        //                 [
        //                     "16493.50",
        //                     "0.006"
        //                 ],
        //                 [
        //                     "16493.00",
        //                     "0.100"
        //                 ]
        //             ],
        //             "a": [
        //                 [
        //                     "16611.00",
        //                     "0.029"
        //                 ],
        //                 [
        //                     "16612.00",
        //                     "0.213"
        //                 ],
        //             ],
        //             "u": 18521288,
        //             "seq": 7961638724
        //         }
        //     }
        //
        Object type = this.safeString(message, "type");
        Object isSnapshot = (Helpers.isEqual(type, "snapshot"));
        Object data = this.safeDict(message, "data", new java.util.HashMap<String, Object>() {{}});
        Object marketId = this.safeString(data, "s");
        Object market = this.safeMarket(marketId, null, null);
        Object symbol = Helpers.GetValue(market, "symbol");
        Object timestamp = this.safeIntegerProduct(message, "ts", 0.001);
        if (!Helpers.isTrue((Helpers.inOp(this.orderbooks, symbol))))
        {
            Helpers.addElementToObject(this.orderbooks, symbol, this.orderBook());
        }
        Object orderbook = Helpers.GetValue(this.orderbooks, symbol);
        if (Helpers.isTrue(isSnapshot))
        {
            Object snapshot = this.parseOrderBook(data, symbol, timestamp, "b", "a");
            Helpers.callDynamically(orderbook, "reset", new Object[]{snapshot});
        } else
        {
            Object asks = this.safeList(data, "a", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            Object bids = this.safeList(data, "b", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            this.handleDeltas(Helpers.GetValue(orderbook, "asks"), asks);
            this.handleDeltas(Helpers.GetValue(orderbook, "bids"), bids);
            Helpers.addElementToObject(orderbook, "timestamp", timestamp);
            Helpers.addElementToObject(orderbook, "datetime", this.iso8601(timestamp));
        }
        Object messageHash = Helpers.add(Helpers.add("orderbook", ":"), symbol);
        Helpers.addElementToObject(this.orderbooks, symbol, orderbook);
        client.resolve(orderbook, messageHash);
    }

