    /**
     * @method
     * @name apex#watchOHLCVForSymbols
     * @description watches historical candlestick data containing the open, high, low, and close price, and the volume of a market
     * @see https://api-docs.pro.apex.exchange/#websocket-v3-for-omni-websocket-endpoint
     * @param {string[][]} symbolsAndTimeframes array of arrays containing unified symbols and timeframes to fetch OHLCV data for, example [['BTC/USDT', '1m'], ['LTC/USDT', '5m']]
     * @param {int} [since] timestamp in ms of the earliest candle to fetch
     * @param {int} [limit] the maximum amount of candles to fetch
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} A list of candles ordered as timestamp, open, high, low, close, volume
     */
    public java.util.concurrent.CompletableFuture<Object> watchOHLCVForSymbols(Object symbolsAndTimeframes, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object since = Helpers.getArg(optionalArgs, 0, null);
            Object limit = Helpers.getArg(optionalArgs, 1, null);
            Object parameters = Helpers.getArg(optionalArgs, 2, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.isEqual(this.markets, null)))
            {
                (this.loadMarkets()).join();
            }
            Object url = this.getWsPublicUrl();
            Object rawHashes = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            Object messageHashes = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(symbolsAndTimeframes)); i++)
            {
                Object data = Helpers.GetValue(symbolsAndTimeframes, i);
                Object symbolString = this.safeString(data, 0);
                Object market = this.market(((String)symbolString));
                symbolString = Helpers.GetValue(market, "id2");
                Object unfiedTimeframe = this.safeString(data, 1, "1");
                Object timeframeId = this.safeString(this.timeframes, unfiedTimeframe, unfiedTimeframe);
                ((java.util.List<Object>)rawHashes).add(Helpers.add(Helpers.add(Helpers.add("candle.", timeframeId), "."), symbolString));
                ((java.util.List<Object>)messageHashes).add(Helpers.add(Helpers.add(Helpers.add("ohlcv::", Helpers.GetValue(market, "symbol")), "::"), unfiedTimeframe));
            }
            var symboltimeframestoredVariable = (this.watchTopics(url, messageHashes, rawHashes, parameters)).join();
            var symbol = ((java.util.List<Object>) symboltimeframestoredVariable).get(0);
            var timeframe = ((java.util.List<Object>) symboltimeframestoredVariable).get(1);
            var stored = ((java.util.List<Object>) symboltimeframestoredVariable).get(2);
            if (Helpers.isTrue(this.newUpdates))
            {
                limit = Helpers.callDynamically(stored, "getLimit", new Object[]{symbol, limit});
            }
            Object filtered = this.filterBySinceLimit(stored, since, limit, 0, true);
            return this.createOHLCVObject(symbol, timeframe, filtered);
        });

    }

    public void handleOHLCV(Client client, Object message)
    {
        //
        //     {
        //         "topic": "candle.5.BTCUSDT",
        //         "data": [
        //             {
        //                 "start": 1672324800000,
        //                 "end": 1672325099999,
        //                 "interval": "5",
        //                 "open": "16649.5",
        //                 "close": "16677",
        //                 "high": "16677",
        //                 "low": "16608",
        //                 "volume": "2.081",
        //                 "turnover": "34666.4005",
        //                 "confirm": false,
        //                 "timestamp": 1672324988882
        //             }
        //         ],
        //         "ts": 1672324988882,
        //         "type": "snapshot"
        //     }
        //
        Object data = this.safeValue(message, "data", new java.util.HashMap<String, Object>() {{}});
        Object topic = this.safeString(message, "topic");
        Object topicParts = Helpers.split(((String)topic), ".");
        Object topicLength = Helpers.getArrayLength(topicParts);
        Object timeframeId = this.safeString(topicParts, 1);
        Object timeframe = this.findTimeframe(timeframeId);
        Object marketId = this.safeString(topicParts, Helpers.subtract(topicLength, 1));
        Object isSpot = Helpers.isGreaterThan(Helpers.getIndexOf(client.url, "spot"), Helpers.opNeg(1));
        Object marketType = ((Helpers.isTrue(isSpot))) ? "spot" : "contract";
        Object market = this.safeMarket(marketId, null, null, marketType);
        Object symbol = Helpers.GetValue(market, "symbol");
        if (!Helpers.isTrue((Helpers.inOp(this.ohlcvs, symbol))))
        {
            Helpers.addElementToObject(this.ohlcvs, symbol, new java.util.HashMap<String, Object>() {{}});
        }
        if (!Helpers.isTrue((Helpers.inOp(Helpers.GetValue(this.ohlcvs, symbol), ((String)timeframe)))))
        {
            Object limit = this.safeInteger(this.options, "OHLCVLimit", 1000);
            Helpers.addElementToObject(Helpers.GetValue(this.ohlcvs, symbol), ((String)timeframe), new ArrayCache.ArrayCacheByTimestamp(((Number)limit).intValue()));
        }
        Object stored = Helpers.GetValue(Helpers.GetValue(this.ohlcvs, symbol), ((String)timeframe));
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(data)); i++)
        {
            Object parsed = this.parseWsOHLCV(Helpers.GetValue(data, i));
            Helpers.callDynamically(stored, "append", new Object[]{parsed});
        }
        Object messageHash = Helpers.add(Helpers.add(Helpers.add("ohlcv::", symbol), "::"), timeframe);
        Object resolveData = new java.util.ArrayList<Object>(java.util.Arrays.asList(symbol, timeframe, stored));
        client.resolve(resolveData, messageHash);
    }

